```

### Test 3: error_max_turns maps to max_turns category
```typescript
it('maps error_max_turns to max_turns category', async () => {
  const events = await collectEvents(
    makeResultMessage('error_max_turns', ['Turn limit reached']),
    SESSION_ID, makeSession(), makeToolState()
  );
  const errorEvent = events.find(e => e.type === 'error');
  expect(errorEvent?.data).toMatchObject({ category: 'max_turns' });
