```

### Test 4: error_max_budget_usd maps to budget_exceeded category
```typescript
it('maps error_max_budget_usd to budget_exceeded category', async () => {
  const events = await collectEvents(
    makeResultMessage('error_max_budget_usd', ['Budget exceeded']),
    SESSION_ID, makeSession(), makeToolState()
  );
  const errorEvent = events.find(e => e.type === 'error');
  expect(errorEvent?.data).toMatchObject({ category: 'budget_exceeded' });
});
```

### Test 5: error_max_structured_output_retries maps to output_format_error category
```typescript
it('maps error_max_structured_output_retries to output_format_error', async () => {
  const events = await collectEvents(
    makeResultMessage('error_max_structured_output_retries', ['Output error']),
    SESSION_ID, makeSession(), makeToolState()
  );
  const errorEvent = events.find(e => e.type === 'error');
  expect(errorEvent?.data).toMatchObject({ category: 'output_format_error' });
});
```

### Test 6: Empty errors array uses fallback message
```typescript
it('uses fallback message when errors array is empty', async () => {
  const events = await collectEvents(
    makeResultMessage('error_during_execution', []),
    SESSION_ID, makeSession(), makeToolState()
  );
  const errorEvent = events.find(e => e.type === 'error');
  expect((errorEvent?.data as { message: string }).message).toBe('An unexpected error occurred.');
});
```

### Test 7: Session status includes cost/tokens even on error
```typescript
it('includes session status data even when result is error', async () => {
  const events = await collectEvents(
    makeResultMessage('error_max_turns', ['Max turns']),
    SESSION_ID, makeSession(), makeToolState()
  );
  const statusEvent = events[0];
  expect((statusEvent.data as { costUsd: number }).costUsd).toBe(0.001);
});
```

## Acceptance Criteria

- All 7 tests pass with `pnpm vitest run <path-to-test-file>`
- Tests cover all four error subtypes plus success and edge case (empty errors)
- No tests use arbitrary timeouts or implementation-detail assertions

Update the error event handler in `apps/client/src/layers/features/chat/model/stream-event-handler.ts` to distinguish categorized SDK errors from uncategorized transport errors.

## Changes

### Replace the error case (lines 279-284)

The current handler:

```typescript
case 'error': {
  const { message } = data as ErrorEvent;
  setError(message);
  setStatus('error');
  break;
}
```

Replace with:

```typescript
case 'error': {
  const errorData = data as ErrorEvent;
  // For categorized SDK errors, render inline in the message stream
  if (errorData.category) {
    currentPartsRef.current.push({
      type: 'error',
      message: errorData.message,
      category: errorData.category,
      details: errorData.details,
    });
    updateAssistantMessage(assistantId);
  } else {
    // Transport-level errors without category — use existing banner
    setError(errorData.message);
  }
  setStatus('error');
  break;
}
```

**Behavioral change:**
- SDK result errors (which always have `category` set by the mapper) append an `ErrorPart` to the current assistant message's parts array and trigger a re-render via `updateAssistantMessage`
- Transport/network errors (which never have `category`) continue using the existing `setError()` banner path
- Both paths set `setStatus('error')` to update the session status indicator

### Verify imports

Ensure `ErrorEvent` is imported from `@dorkos/shared/schemas` (or wherever the stream-event-handler currently imports it). The `ErrorEvent` type already includes the new `category` and `details` optional fields from task 1.1, so no import changes should be needed.

## Acceptance Criteria

- When an `error` event with `category` is received, an `ErrorPart` is pushed to `currentPartsRef.current` and `updateAssistantMessage(assistantId)` is called
- When an `error` event without `category` is received, `setError(message)` is called (banner path, unchanged)
- `setStatus('error')` is always called regardless of category presence
- `pnpm typecheck` passes

Create a new component at `apps/client/src/layers/features/chat/ui/ErrorMessageBlock.tsx` that renders inline error blocks in the assistant message stream.

## Full Component Code

```typescript
import { useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { AlertCircle, ChevronDown, RotateCcw } from 'lucide-react';
import { Button } from '@/layers/shared/ui';
import { cn } from '@/layers/shared/lib';
import type { ErrorCategory } from '@dorkos/shared/types';

/** User-facing copy for each error category. */
const ERROR_COPY: Record<ErrorCategory, { heading: string; description: string }> = {
  max_turns: {
    heading: 'Turn limit reached',
    description: 'The agent ran for its maximum number of turns.',
  },
  execution_error: {
    heading: 'Agent stopped unexpectedly',
    description: 'An error occurred during execution.',
  },
  budget_exceeded: {
    heading: 'Cost limit reached',
    description: 'This session exceeded its budget.',
  },
  output_format_error: {
    heading: 'Output format error',
    description: "The agent couldn't produce the required output format.",
  },
};

/** Whether an error category supports retry. */
const RETRYABLE_CATEGORIES: Set<ErrorCategory> = new Set(['execution_error']);

interface ErrorMessageBlockProps {
  category?: ErrorCategory;
  message: string;
  details?: string;
  onRetry?: () => void;
}

/**
 * Inline error block rendered in the assistant message stream.
 * Shows category-specific heading, description, optional retry button,
 * and collapsible raw error details.
 */
export function ErrorMessageBlock({ category, message, details, onRetry }: ErrorMessageBlockProps) {
  const [detailsOpen, setDetailsOpen] = useState(false);
  const copy = category ? ERROR_COPY[category] : null;
  const canRetry = category && RETRYABLE_CATEGORIES.has(category) && onRetry;

  return (
    <div className="my-2 rounded-xl border border-red-500/20 bg-red-500/5 p-4 dark:border-red-400/20 dark:bg-red-400/5">
      <div className="flex items-start gap-3">
        <AlertCircle className="mt-0.5 size-5 shrink-0 text-red-500 dark:text-red-400" />
        <div className="min-w-0 flex-1 space-y-1">
          <p className="text-sm font-medium text-red-600 dark:text-red-400">
            {copy?.heading ?? 'Error'}
          </p>
          <p className="text-sm text-muted-foreground">
            {copy?.description ?? message}
          </p>

          {/* Collapsible details */}
          {details && (
            <button
              type="button"
              onClick={() => setDetailsOpen(!detailsOpen)}
              className="mt-2 flex items-center gap-1 text-xs text-muted-foreground/70 hover:text-muted-foreground"
            >
              <ChevronDown
                className={cn('size-3 transition-transform', detailsOpen && 'rotate-180')}
              />
              Details
            </button>
          )}
          <AnimatePresence>
            {detailsOpen && details && (
              <motion.pre
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                transition={{ duration: 0.2, ease: [0.4, 0, 0.2, 1] }}
                className="overflow-hidden whitespace-pre-wrap rounded-md bg-muted/50 p-2 font-mono text-xs text-muted-foreground"
              >
                {details}
              </motion.pre>
            )}
          </AnimatePresence>

          {/* Retry button */}
          {canRetry && (
            <Button
              variant="outline"
              size="sm"
              onClick={onRetry}
              className="mt-3 gap-1.5"
            >
              <RotateCcw className="size-3.5" />
              Retry
            </Button>
          )}
        </div>
      </div>
    </div>
  );
}
```

## Design System Compliance

- `rounded-xl` — 16px card radius per design system
- `p-4` — 16px padding, 8pt grid
- `my-2` — 8px vertical margin
- `text-sm` for body, `text-xs` for details
- Muted red tint via `bg-red-500/5` — subtle, not alarming
- `border-red-500/20` — visible but not dominant
- Dark mode variants with `dark:` prefix
- Motion animation for collapsible details matching ToolCallCard expand/collapse pattern
- Lucide icons (AlertCircle, ChevronDown, RotateCcw) — already used in the client

## Import Path Verification

Verify the import path for `ErrorCategory`. Check how other features import shared types — it may be `@dorkos/shared/types` or `@dorkos/shared/schemas`. Match the existing convention.

## Acceptance Criteria

- Component renders with all four category variants showing correct heading and description
- Retry button appears only when `category` is `execution_error` AND `onRetry` is provided
- Retry button does not appear for `max_turns`, `budget_exceeded`, or `output_format_error`
- Collapsible details toggle works — hidden by default, visible after clicking "Details"
- When no `category` is provided, shows "Error" heading and uses `message` as description
- Component follows FSD layer rules — only imports from `shared/` layer
- `pnpm typecheck` passes

